from __future__ import annotations

import asyncio
import logging
from datetime import datetime, timezone
from typing import Any
from uuid import UUID

import jwt
from fastapi import APIRouter, Query, WebSocket, WebSocketDisconnect, status
from sqlalchemy import select
from sqlalchemy.orm import aliased

from ..config import settings
from ..db import SessionLocal
from ..models import Message, RoomMember, User
from ..redis_client import redis_client
from ..services.messages import create_message as create_message_svc
from ..services.messages import message_envelope
from . import presence
from .manager import manager

log = logging.getLogger(__name__)

router = APIRouter(tags=["ws"])

IDLE_LIMIT_S = 60
WATCHDOG_TICK_S = 10
TYPING_WINDOW_S = 5
REPLAY_MAX_MESSAGES = 500


def _now_iso() -> str:
    return datetime.now(tz=timezone.utc).isoformat()


def _decode_token(token: str) -> UUID | None:
    try:
        payload = jwt.decode(
            token, settings.jwt_secret, algorithms=[settings.jwt_algorithm]
        )
        return UUID(str(payload["sub"]))
    except (jwt.PyJWTError, KeyError, ValueError):
        return None


async def _authenticate(websocket: WebSocket, token: str | None) -> UUID | None:
    if not token:
        auth_header = websocket.headers.get("authorization", "")
        if auth_header.lower().startswith("bearer "):
            token = auth_header.split(" ", 1)[1]
    if not token:
        return None
    return _decode_token(token)


async def _ensure_user(user_id: UUID, username_hint: str | None = None) -> None:
    async with SessionLocal() as session:
        user = await session.get(User, user_id)
        if user is None:
            session.add(
                User(id=user_id, username=username_hint or f"u_{str(user_id)[:8]}")
            )
            await session.commit()


async def _room_peers(room_id: UUID) -> list[UUID]:
    async with SessionLocal() as session:
        stmt = select(RoomMember.user_id).where(RoomMember.room_id == room_id)
        return list((await session.execute(stmt)).scalars().all())


async def _all_my_peers(user_id: UUID) -> list[UUID]:
    """All distinct users who share at least one room with this user."""
    async with SessionLocal() as session:
        m_self = aliased(RoomMember)
        m_peer = aliased(RoomMember)
        stmt = (
            select(m_peer.user_id)
            .join(m_self, m_self.room_id == m_peer.room_id)
            .where(m_self.user_id == user_id)
            .where(m_peer.user_id != user_id)
            .distinct()
        )
        return list((await session.execute(stmt)).scalars().all())


async def _is_member(room_id: UUID, user_id: UUID) -> bool:
    async with SessionLocal() as session:
        m = await session.get(
            RoomMember, {"room_id": room_id, "user_id": user_id}
        )
        return m is not None


async def _replay(
    websocket: WebSocket, user_id: UUID, room_cursors: dict[str, str]
) -> None:
    async with SessionLocal() as session:
        my_rooms_stmt = select(RoomMember.room_id).where(
            RoomMember.user_id == user_id
        )
        my_rooms = set((await session.execute(my_rooms_stmt)).scalars().all())

        for room_id_str, cursor_iso in room_cursors.items():
            try:
                room_id = UUID(str(room_id_str))
                since = datetime.fromisoformat(str(cursor_iso))
            except (ValueError, TypeError):
                continue
            if room_id not in my_rooms:
                continue

            stmt = (
                select(Message)
                .where(
                    Message.room_id == room_id,
                    Message.created_at > since,
                    Message.deleted_at.is_(None),
                )
                .order_by(Message.created_at.asc(), Message.id.asc())
                .limit(REPLAY_MAX_MESSAGES)
            )
            rows = list((await session.execute(stmt)).scalars().all())
            for m in rows:
                await websocket.send_json(message_envelope(m))

    await websocket.send_json({"op": "replay_complete", "server_ts": _now_iso()})


async def _handle_send(
    websocket: WebSocket, user_id: UUID, msg: dict[str, Any]
) -> None:
    try:
        room_id = UUID(str(msg["room_id"]))
        body = str(msg["body"])
    except (KeyError, ValueError, TypeError) as e:
        await websocket.send_json(
            {"op": "error", "detail": f"bad send envelope: {e}"}
        )
        return

    client_msg_id = msg.get("client_msg_id")

    async with SessionLocal() as session:
        membership = await session.get(
            RoomMember, {"room_id": room_id, "user_id": user_id}
        )
        if membership is None:
            await websocket.send_json(
                {
                    "op": "error",
                    "detail": "not a member of this room",
                    "client_msg_id": client_msg_id,
                }
            )
            return
        created, recipients = await create_message_svc(
            session, room_id, user_id, body
        )

    await manager.broadcast_to_users(
        recipients, message_envelope(created, client_msg_id=client_msg_id)
    )


async def _handle_typing(user_id: UUID, msg: dict[str, Any]) -> None:
    try:
        room_id = UUID(str(msg["room_id"]))
    except (KeyError, ValueError, TypeError):
        return
    if not await _is_member(room_id, user_id):
        return
    peers = [p for p in await _room_peers(room_id) if p != user_id]
    if not peers:
        return
    await manager.broadcast_to_users(
        peers,
        {
            "op": "typing",
            "room_id": str(room_id),
            "user_id": str(user_id),
            "expires_at": datetime.now(tz=timezone.utc).timestamp()
            + TYPING_WINDOW_S,
        },
    )


async def _handle_read(user_id: UUID, msg: dict[str, Any]) -> None:
    try:
        room_id = UUID(str(msg["room_id"]))
        message_id = UUID(str(msg["message_id"]))
    except (KeyError, ValueError, TypeError):
        return
    async with SessionLocal() as session:
        membership = await session.get(
            RoomMember, {"room_id": room_id, "user_id": user_id}
        )
        if membership is None:
            return
        membership.last_read_message_id = message_id
        await session.commit()
    peers = [p for p in await _room_peers(room_id) if p != user_id]
    if peers:
        await manager.broadcast_to_users(
            peers,
            {
                "op": "read",
                "room_id": str(room_id),
                "user_id": str(user_id),
                "message_id": str(message_id),
            },
        )


@router.websocket("/v1/ws")
async def ws_endpoint(
    websocket: WebSocket,
    token: str | None = Query(default=None),
) -> None:
    user_id = await _authenticate(websocket, token)
    if user_id is None:
        await websocket.close(
            code=status.WS_1008_POLICY_VIOLATION, reason="unauthenticated"
        )
        return

    await _ensure_user(user_id)
    await websocket.accept()

    first_local = manager.register(user_id, websocket)
    await presence.mark_online(redis_client, user_id)

    await websocket.send_json(
        {"op": "hello", "user_id": str(user_id), "server_ts": _now_iso()}
    )

    if first_local:
        peers = await _all_my_peers(user_id)
        await manager.broadcast_to_users(
            peers, {"op": "presence", "user_id": str(user_id), "state": "online"}
        )

    loop = asyncio.get_running_loop()
    last_activity = loop.time()

    async def watchdog() -> None:
        while True:
            await asyncio.sleep(WATCHDOG_TICK_S)
            if loop.time() - last_activity > IDLE_LIMIT_S:
                try:
                    await websocket.close(
                        code=status.WS_1008_POLICY_VIOLATION,
                        reason="idle timeout",
                    )
                except Exception:
                    pass
                return

    watchdog_task = asyncio.create_task(watchdog())

    try:
        while True:
            try:
                incoming = await websocket.receive_json()
            except (ValueError, TypeError):
                await websocket.send_json(
                    {"op": "error", "detail": "invalid json"}
                )
                continue

            last_activity = loop.time()
            await presence.refresh(redis_client, user_id)

            op = incoming.get("op") if isinstance(incoming, dict) else None

            if op == "ping":
                await websocket.send_json({"op": "pong", "server_ts": _now_iso()})
            elif op == "resume":
                cursors = incoming.get("room_cursors", {}) or {}
                if isinstance(cursors, dict):
                    await _replay(websocket, user_id, cursors)
            elif op == "send":
                await _handle_send(websocket, user_id, incoming)
            elif op == "typing":
                await _handle_typing(user_id, incoming)
            elif op == "read":
                await _handle_read(user_id, incoming)
            elif op in ("ack", "view_attachment"):
                # Accepted in M2d; no-op. Hooks for v2.
                pass
            else:
                await websocket.send_json(
                    {"op": "error", "detail": f"unknown op: {op!r}"}
                )
    except WebSocketDisconnect:
        pass
    except Exception as e:
        log.exception("ws error for user %s: %s", user_id, e)
    finally:
        watchdog_task.cancel()
        try:
            await watchdog_task
        except (asyncio.CancelledError, Exception):
            pass

        last_local = manager.unregister(user_id, websocket)
        if last_local:
            await presence.mark_offline(redis_client, user_id)
            peers = await _all_my_peers(user_id)
            await manager.broadcast_to_users(
                peers,
                {"op": "presence", "user_id": str(user_id), "state": "offline"},
            )

